import React, { useState, useEffect, useRef, useCallback } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import { useSocket } from "../context/SocketContext";
import { useAppSettings } from "../context/AppSettingsContext";

import CallModal from "../components/CallModal";
import IncomingCallAlert from "../components/IncomingCallAlert";
import SettingsPanel from "../components/SettingsPanel";

const API = process.env.REACT_APP_SERVER_URL || "http://localhost:5000";

/* ───────────────────────── HELPERS ───────────────────────── */

const formatTime = (dateStr) =>
  new Date(dateStr).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

const formatSize = (bytes) => {
  if (bytes < 1024) return bytes + " B";
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
  return (bytes / (1024 * 1024)).toFixed(1) + " MB";
};

/* ───────────────────────── COMPONENTS ───────────────────────── */

const Avatar = ({ user, size = "md" }) => {
  const sizes = {
    sm: "w-8 h-8 text-xs",
    md: "w-12 h-12 text-base",
    lg: "w-16 h-16 text-xl",
  };

  const src = user?.avatar ? API + user.avatar : null;

  return src ? (
    <img src={src} className={`${sizes[size]} rounded-xl object-cover`} />
  ) : (
    <div className={`${sizes[size]} bg-purple-500 flex items-center justify-center text-white rounded-xl`}>
      {user?.username?.[0]?.toUpperCase() || "?"}
    </div>
  );
};

/* ───────────────────────── MAIN PAGE ───────────────────────── */

export default function ChatPage() {
  const { user, logout } = useAuth();
  const { socket, isOnline: isOnlineRaw } = useSocket();
  const { settings } = useAppSettings();

  /* ─ STATE ─ */
  const [contacts, setContacts] = useState([]);
  const [activeContact, setActiveContact] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");

  const [unreadMap, setUnreadMap] = useState({});
  const [lastMsgMap, setLastMsgMap] = useState({});
  const [activeTab, setActiveTab] = useState("chats");

  const [incomingCall, setIncomingCall] = useState(null);
  const [callData, setCallData] = useState(null);

  const bottomRef = useRef();

  /* ───────────────────────── LOGIC ───────────────────────── */

  const isOnline = (uid) => isOnlineRaw?.(uid);

  /* FETCH CONTACTS */
  useEffect(() => {
    axios.get("/api/users").then((r) => setContacts(r.data.users));
  }, []);

  /* LOAD MESSAGES */
  useEffect(() => {
    if (!activeContact) return;

    axios.get("/api/messages/" + activeContact._id).then((r) => {
      setMessages(r.data.messages);
      setUnreadMap((prev) => ({ ...prev, [activeContact._id]: 0 }));
    });
  }, [activeContact]);

  /* AUTO SCROLL */
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  /* SOCKET EVENTS */
  useEffect(() => {
    if (!socket) return;

    socket.on("receiveMessage", (msg) => {
      const senderId = msg.sender._id || msg.sender;

      if (activeContact && senderId === activeContact._id) {
        setMessages((prev) => [...prev, msg]);
      } else {
        setUnreadMap((prev) => ({
          ...prev,
          [senderId]: (prev[senderId] || 0) + 1,
        }));
      }

      setLastMsgMap((prev) => ({ ...prev, [senderId]: msg }));
    });

    return () => socket.off("receiveMessage");
  }, [socket, activeContact]);

  /* SEND MESSAGE */
  const sendMessage = useCallback(() => {
    if (!text.trim() || !activeContact) return;

    socket.emit("sendMessage", {
      receiverId: activeContact._id,
      content: text,
      type: "text",
    });

    setText("");
  }, [text, activeContact, socket]);

  /* ───────────────────────── UI ───────────────────────── */

  return (
    <div className="flex h-screen bg-[#0f0f13] text-white">

      {/* SIDEBAR */}
      <aside className="w-16 bg-[#111218] flex flex-col items-center py-6">
        <button onClick={() => setActiveTab("chats")}>💬</button>
        <button onClick={() => setActiveTab("contacts")}>👥</button>
        <button onClick={() => setActiveTab("settings")}>⚙️</button>
      </aside>

      {/* LEFT PANEL */}
      <section className="w-80 bg-[#1a1b23] overflow-y-auto">
        <h2 className="p-4 font-bold">Chats</h2>

        {contacts.map((c) => (
          <div
            key={c._id}
            onClick={() => setActiveContact(c)}
            className="p-3 cursor-pointer hover:bg-white/10 flex gap-3"
          >
            <Avatar user={c} />
            <div>
              <p>{c.username}</p>
              <p className="text-xs opacity-50">
                {lastMsgMap[c._id]?.content || "No messages"}
              </p>
            </div>
          </div>
        ))}
      </section>

      {/* CHAT PANEL */}
      <section className="flex-1 flex flex-col">

        {activeContact ? (
          <>
            {/* HEADER */}
            <div className="p-4 border-b border-white/10 flex justify-between">
              <div className="flex gap-3 items-center">
                <Avatar user={activeContact} size="sm" />
                <span>{activeContact.username}</span>
              </div>

              <button onClick={() => setCallData({ userId: activeContact._id })}>
                📞
              </button>
            </div>

            {/* MESSAGES */}
            <div className="flex-1 overflow-y-auto p-4">
              {messages.map((m, i) => {
                const isSent = (m.sender._id || m.sender) === user._id;

                return (
                  <div
                    key={i}
                    className={`mb-2 ${isSent ? "text-right" : ""}`}
                  >
                    <span
                      className={`inline-block px-3 py-2 rounded-xl ${
                        isSent ? "bg-purple-600" : "bg-white/10"
                      }`}
                    >
                      {m.content}
                    </span>
                  </div>
                );
              })}
              <div ref={bottomRef} />
            </div>

            {/* INPUT */}
            <div className="p-4 flex gap-2">
              <input
                className="flex-1 p-2 rounded bg-white/10 outline-none"
                value={text}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && sendMessage()}
              />
              <button
                onClick={sendMessage}
                className="bg-purple-600 px-4 rounded"
              >
                Send
              </button>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center opacity-50">
            Select a chat
          </div>
        )}
      </section>

      {/* CALL MODAL */}
      {callData && (
        <CallModal callData={callData} onEnd={() => setCallData(null)} />
      )}

      {/* INCOMING CALL */}
      {incomingCall && (
        <IncomingCallAlert
          callData={incomingCall}
          onAccept={() => setIncomingCall(null)}
          onReject={() => setIncomingCall(null)}
        />
      )}
    </div>
  );
}
